    const template: RigTemplate = {
      engines: [
        { id: 'draft', designId: 'draft', givens: { writ: '$writ' } },
        { id: 'implement', designId: 'implement', upstream: ['draft'], givens: { writ: '$writ', role: '$vars.role' } },
